const WebSocket = require\('ws'\);
const http = require\('http'\);

// ── Helpers ──

function getJSON\(url\) {
  return new Promise\(\(resolve, reject\) => {
    http.get\(url, \(res\) => {
      let data = '';
      res.on\('data', \(chunk\) => \(data += chunk\)\);
      res.on\('end', \(\) => {
        try { resolve\(JSON.parse\(data\)\); }
        catch \(e\) { reject\(new Error\('Failed to parse JSON from ' + url + ': ' + data\)\); }
      }\);
    }\).on\('error', reject\);
  }\);
}

let msgId = 1;
let ws;
const pending = new Map\(\);

function send\(method, params\) {
  params = params || {};
  return new Promise\(\(resolve, reject\) => {
    const id = msgId++;
    const timeout = setTimeout\(\(\) => {
      pending.delete\(id\);
      reject\(new Error\('Timeout for ' + method\)\);
    }, 15000\);
    pending.set\(id, { resolve, reject, timeout }\);
    ws.send\(JSON.stringify\({ id, method, params }\)\);
  }\);
}

async function evaluate\(expression\) {
  const res = await send\('Runtime.evaluate', {
    expression: expression,
    awaitPromise: true,
    returnByValue: true,
  }\);
  if \(res.result && res.result.exceptionDetails\) {
    var desc = \(res.result.exceptionDetails.exception && res.result.exceptionDetails.exception.description\) ||
               res.result.exceptionDetails.text ||
               JSON.stringify\(res.result.exceptionDetails\);
    throw new Error\('JS Exception: ' + desc\);
  }
  return res.result && res.result.result && res.result.result.value;
}

async function invokeIpc\(channel\) {
  var args = Array.prototype.slice.call\(arguments, 1\);
  var argsStr = args.map\(function\(a\) { return JSON.stringify\(a\); }\).join\(', '\);
  var expr = "window.electron.ipcRenderer.invoke\('" + channel + "'" + \(args.length ? ', ' + argsStr : ''\) + "\)";
  return evaluate\(expr\);
}

